import pandas as pd,json,re,ast
m=pd.read_csv('market.csv', dtype={'qid':str})
# pick Jan resolution or near Jan qids from resolution_date if available string
rows=m[m['resolution_date'].astype(str).str.contains('2026-01|2025-12', na=False)]
# gather predicted names of length >4
cands=[]
for _,r in rows.iterrows():
    try:
        d=json.loads(r['market_aggregate']) if isinstance(r['market_aggregate'],str) else {}
    except Exception:
        d={}
    for k in d:
        if len(k)>4 and k.lower() not in {'israel','russia','china','india','qatar','turkey','italy','japan','mexico','canada'}:
            cands.append((r['qid'],r['title'],k))
arts=[]
for line in open('articles/2025/12/27/articles.jsonl'):
    a=json.loads(line); title=a.get('title') or ''; content=a.get('content') or ''
    arts.append((a.get('source'),title,(title+'\\n'+content).lower()))
seen=set(); hits=[]
for qid,title,c in cands:
    cl=c.lower()
    if len(cl)<5: continue
    for src,at,txt in arts:
        if cl in txt:
            key=(qid,c,at)
            if key not in seen:
                hits.append((qid,c,src,at,title))
                seen.add(key)
            break
for h in hits[:200]:
    print('\\t'.join(h))
print('hits',len(hits),'jan rows',len(rows))
PY"

